  final _noteFocusNode = FocusNode();
  final _cryptoFocus = FocusNode();
  final _baseFocus = FocusNode();

  Amount? _amountToSend;
  Amount? _cachedAmountToSend;
  String? _address;

  bool _addressToggleFlag = false;

  bool _cryptoAmountChangeLock = false;
  late VoidCallback onCryptoAmountChanged;

  final updateFeesTimerDuration = const Duration(milliseconds: 500);

  Timer? _cryptoAmountChangedFeeUpdateTimer;
  Timer? _baseAmountChangedFeeUpdateTimer;
  late Future<String> _calculateFeesFuture;
  String cachedFees = "";

  void _onTokenSendViewPasteAddressFieldButtonPressed() async {
    final ClipboardData? data = await clipboard.getData(Clipboard.kTextPlain);
    if (data?.text != null && data!.text!.isNotEmpty) {
      String content = data.text!.trim();
      if (content.contains("\n")) {
        content = content.substring(0, content.indexOf("\n"));
      }
      sendToController.text = content.trim();
      _address = content.trim();

      _updatePreviewButtonState(_address, _amountToSend);
      setState(() {
        _addressToggleFlag = sendToController.text.isNotEmpty;
      });
    }
  }

  void _onTokenSendViewScanQrButtonPressed() async {
    try {
      if (FocusScope.of(context).hasFocus) {
        FocusScope.of(context).unfocus();
        await Future<void>.delayed(const Duration(milliseconds: 75));
      }

      final qrResult = await ref.read(pBarcodeScanner).scan(context: context);

      Logging.instance.d("qrResult content: ${qrResult.rawContent}");
      if (qrResult.rawContent == null) return;

      final paymentData = AddressUtils.parsePaymentUri(
        qrResult.rawContent!,
        logging: Logging.instance,
      );

      Logging.instance.d("qrResult parsed: $paymentData");

      if (paymentData != null) {
        // auto fill address
        _address = paymentData.address.trim();
        sendToController.text = _address!;

        // autofill notes field
        if (paymentData.message != null) {
          noteController.text = paymentData.message!;
        } else if (paymentData.label != null) {
          noteController.text = paymentData.label!;
        }

        // autofill amount field
        if (paymentData.amount != null) {
          final tokenWallet = ref.read(pCurrentSolanaTokenWallet);
          if (tokenWallet != null) {
            final Amount amount = Decimal.parse(
              paymentData.amount!,
            ).toAmount(fractionDigits: tokenWallet.tokenDecimals);
            cryptoAmountController.text = ref
                .read(pAmountFormatter(Solana(CryptoCurrencyNetwork.main)))
                .format(
                  amount,
                  withUnitName: false,
                  indicatePrecisionLoss: false,
                );
            _amountToSend = amount;
          }
        }

        _updatePreviewButtonState(_address, _amountToSend);
        setState(() {
          _addressToggleFlag = sendToController.text.isNotEmpty;
        });

        // now check for non standard encoded basic address
      } else {
        _address = qrResult.rawContent!.split("\n").first.trim();
        sendToController.text = _address ?? "";

        _updatePreviewButtonState(_address, _amountToSend);
        setState(() {
          _addressToggleFlag = sendToController.text.isNotEmpty;
        });
      }
    } on PlatformException catch (e, s) {
      if (mounted) {
        try {
          await checkCamPermDeniedMobileAndOpenAppSettings(
            context,
            logging: Logging.instance,
          );
        } catch (e, s) {
          Logging.instance.e(
            "Failed to check cam permissions",
            error: e,
            stackTrace: s,
          );
        }
      } else {
        Logging.instance.w(
          "Failed to get camera permissions while trying to scan qr code in SolTokenSendView: ",
          error: e,
          stackTrace: s,
        );
      }
    }
  }

  void _onFiatAmountFieldChanged(String baseAmountString) {
    final baseAmount = Amount.tryParseFiatString(
      baseAmountString,
      locale: ref.read(localeServiceChangeNotifierProvider).locale,
    );
    if (baseAmount != null) {
      final _price = ref
          .read(priceAnd24hChangeNotifierProvider)
          .getTokenPrice(tokenMint)
          ?.value;

      final tokenWallet = ref.read(pCurrentSolanaTokenWallet);
      if (tokenWallet == null) return;

      if (_price == null || _price == Decimal.zero) {
        _amountToSend = Amount.zero;
      } else {
        _amountToSend = baseAmount <= Amount.zero
            ? Amount.zero
            : Amount.fromDecimal(
                (baseAmount.decimal / _price).toDecimal(
                  scaleOnInfinitePrecision: tokenWallet.tokenDecimals,
                ),
                fractionDigits: tokenWallet.tokenDecimals,
              );
      }
      if (_cachedAmountToSend != null && _cachedAmountToSend == _amountToSend) {
        return;
      }
      _cachedAmountToSend = _amountToSend;

      _cryptoAmountChangeLock = true;
      cryptoAmountController.text = ref
          .read(pAmountFormatter(Solana(CryptoCurrencyNetwork.main)))
          .format(_amountToSend!, withUnitName: false);
      _cryptoAmountChangeLock = false;
    } else {
      _amountToSend = Amount.zero;
      _cryptoAmountChangeLock = true;
      cryptoAmountController.text = "";
      _cryptoAmountChangeLock = false;
    }
    _updatePreviewButtonState(_address, _amountToSend);
  }

  void _cryptoAmountChanged() async {
    if (!_cryptoAmountChangeLock) {
      final tokenWallet = ref.read(pCurrentSolanaTokenWallet);
      if (tokenWallet == null) return;

      final cryptoAmount = Decimal.tryParse(
        cryptoAmountController.text,
      )?.toAmount(fractionDigits: tokenWallet.tokenDecimals);
      if (cryptoAmount != null) {
        _amountToSend = cryptoAmount;
        if (_cachedAmountToSend != null &&
            _cachedAmountToSend == _amountToSend) {
          return;
        }
        _cachedAmountToSend = _amountToSend;

        final price = ref
            .read(priceAnd24hChangeNotifierProvider)
            .getTokenPrice(tokenMint)
            ?.value;

        if (price != null && price > Decimal.zero) {
          baseAmountController.text = (_amountToSend!.decimal * price)
              .toAmount(fractionDigits: 2)
              .fiatString(
                locale: ref.read(localeServiceChangeNotifierProvider).locale,
              );
        }
      } else {
        _amountToSend = null;
        baseAmountController.text = "";
      }

      _updatePreviewButtonState(_address, _amountToSend);

      _cryptoAmountChangedFeeUpdateTimer?.cancel();
      _cryptoAmountChangedFeeUpdateTimer = Timer(updateFeesTimerDuration, () {
        if (mounted) {
          setState(() {
            _calculateFeesFuture = calculateFees();
          });
        }
      });
    }
  }

  void _baseAmountChanged() {
    _baseAmountChangedFeeUpdateTimer?.cancel();
    _baseAmountChangedFeeUpdateTimer = Timer(updateFeesTimerDuration, () {
      if (mounted && !_cryptoFocus.hasFocus) {
        setState(() {
          _calculateFeesFuture = calculateFees();
        });
      }
    });
  }

  String? _updateInvalidAddressText(String address) {
    if (_data != null && _data.contactLabel == address) {
      return null;
    }
    if (address.isNotEmpty) {
      // TODO: Implement Solana address validation.
      // For now, perform basic length check (44 chars is typical for Solana addresses).
      if (address.length < 32 || address.length > 44) {
        return "Invalid address";
      }
    }
    return null;
  }

  void _updatePreviewButtonState(String? address, Amount? amount) {
    // TODO: Implement Solana address validation.
    final isValidAddress =
        address != null &&
        address.isNotEmpty &&
        address.length >= 32 &&
        address.length <= 44;
    ref.read(previewTokenTxButtonStateProvider.state).state =
        (isValidAddress && amount != null && amount > Amount.zero);
  }

  Future<String> calculateFees() async {
    try {
      final wallet = ref.read(pCurrentSolanaTokenWallet);
      if (wallet == null) {
        return "0.000005 SOL";
      }

      final feeObject = await wallet.fees;

      late final BigInt feeRate;

      switch (ref.read(feeRateTypeMobileStateProvider.state).state) {
        case FeeRateType.fast:
          feeRate = feeObject.fast;
          break;
        case FeeRateType.average:
          feeRate = feeObject.medium;
          break;
        case FeeRateType.slow:
          feeRate = feeObject.slow;
          break;
        default:
          feeRate = BigInt.from(-1);
      }

      final Amount fee = await wallet.estimateFeeFor(Amount.zero, feeRate);
      cachedFees = ref
          .read(pAmountFormatter(Solana(CryptoCurrencyNetwork.main)))
          .format(fee, withUnitName: true, indicatePrecisionLoss: false);

      return cachedFees;
    } catch (e, s) {
      Logging.instance.w(
        "Failed to calculate Solana token fees: ",
        error: e,
        stackTrace: s,
      );
      // Return minimum fee as fallback.
      return "0.000005 SOL";
    }
  }

  Future<void> _previewTransaction() async {
    // wait for keyboard to disappear
    FocusScope.of(context).unfocus();
    await Future<void>.delayed(const Duration(milliseconds: 100));

    final tokenWallet = ref.read(pCurrentSolanaTokenWallet);
    if (tokenWallet == null) {
      if (mounted) {
        await showDialog<dynamic>(
          context: context,
          useSafeArea: false,
          barrierDismissible: true,
          builder: (context) {
            return StackDialog(
              title: "Error",
              message: "Token wallet not initialized",
              rightButton: TextButton(
                style: Theme.of(context)
                    .extension<StackColors>()!
                    .getSecondaryEnabledButtonStyle(context),
                child: Text(
                  "Ok",
                  style: STextStyles.button(context).copyWith(
                    color: Theme.of(
                      context,
                    ).extension<StackColors>()!.accentColorDark,
                  ),
                ),
                onPressed: () {
                  Navigator.of(context).pop();
                },
              ),
            );
          },
        );
      }
      return;
    }

    final wallet = ref.read(pWallets).getWallet(walletId);
    final Amount amount = _amountToSend!;

    try {
      bool wasCancelled = false;

      if (mounted) {
        unawaited(
          showDialog<void>(
            context: context,
            useSafeArea: false,
            barrierDismissible: false,
            builder: (context) {
              return BuildingTransactionDialog(
                coin: wallet.info.coin,
                isSpark: false,
                onCancel: () {
                  wasCancelled = true;

                  Navigator.of(context).pop();
                },
              );
            },
          ),
        );
      }

      final time = Future<dynamic>.delayed(const Duration(milliseconds: 2500));

      TxData txData;
      Future<TxData> txDataFuture;

      Logging.instance.i(
        "SolTokenSendView: Preparing transaction - amount: ${amount.decimal} "
        "(raw: ${amount.raw}), decimals: ${tokenWallet.tokenDecimals}, "
        "tokenSymbol: ${tokenWallet.tokenSymbol}",
      );

      txDataFuture = tokenWallet.prepareSend(
        txData: TxData(
          recipients: [
            TxRecipient(
              address: _address!,
              amount: amount,
              isChange: false,
              addressType: AddressType.solana,
            ),
          ],
          feeRateType: ref.read(feeRateTypeMobileStateProvider),
          note: noteController.text,
          tokenMint: tokenMint,
          tokenSymbol: tokenWallet.tokenSymbol,
          tokenDecimals: tokenWallet.tokenDecimals,
        ),
      );

      final results = await Future.wait([txDataFuture, time]);

      txData = results.first as TxData;

      if (!wasCancelled && mounted) {
        // pop building dialog
        Navigator.of(context).pop();

        unawaited(
          Navigator.of(context).push(
            RouteGenerator.getRoute(
              shouldUseMaterialRoute: RouteGenerator.useMaterialPageRoute,
              builder: (_) => ConfirmTransactionView(
                txData: txData,
                walletId: walletId,
                isTokenTx: true,
                onSuccess: clearSendForm,
                routeOnSuccessName: SolTokenView.routeName,
              ),
              settings: const RouteSettings(
                name: ConfirmTransactionView.routeName,
              ),
            ),
          ),
        );
      }
    } catch (e, s) {
      Logging.instance.e("$e\n$s", error: e, stackTrace: s);
      if (mounted) {
        // pop building dialog
        Navigator.of(context).pop();

        unawaited(
          showDialog<dynamic>(
            context: context,
            useSafeArea: false,
            barrierDismissible: true,
            builder: (context) {
              return StackDialog(
                title: "Transaction failed",
                message: e.toString(),
                rightButton: TextButton(
                  style: Theme.of(context)
                      .extension<StackColors>()!
                      .getSecondaryEnabledButtonStyle(context),
                  child: Text(
                    "Ok",
                    style: STextStyles.button(context).copyWith(
                      color: Theme.of(
                        context,
                      ).extension<StackColors>()!.accentColorDark,
                    ),
                  ),
                  onPressed: () {
                    Navigator.of(context).pop();
                  },
                ),
              );
            },
          ),
        );
      }
    }
  }

  void clearSendForm() {
    sendToController.text = "";
    cryptoAmountController.text = "";
    baseAmountController.text = "";
    noteController.text = "";
    feeController.text = "";
    _address = "";
    _addressToggleFlag = false;
    if (mounted) {
      setState(() {});
    }
  }

  @override
  void initState() {
    ref.refresh(feeSheetSessionCacheProvider);
    ref.read(feeRateTypeMobileStateProvider.state).state = FeeRateType.slow;

    _calculateFeesFuture = calculateFees();
    _data = widget.autoFillData;
    walletId = widget.walletId;
    tokenMint = widget.tokenMint;
    clipboard = widget.clipboard;

    sendToController = TextEditingController();
    cryptoAmountController = TextEditingController();
    baseAmountController = TextEditingController();
    noteController = TextEditingController();
    feeController = TextEditingController();

    onCryptoAmountChanged = _cryptoAmountChanged;
    cryptoAmountController.addListener(onCryptoAmountChanged);
    baseAmountController.addListener(_baseAmountChanged);

    if (_data != null) {
      if (_data.amount != null) {
        cryptoAmountController.text = _data.amount!.toString();
      }
      sendToController.text = _data.contactLabel;
      _address = _data.address.trim();
      _addressToggleFlag = true;
    }

    super.initState();
  }

  @override
  void dispose() {
    _cryptoAmountChangedFeeUpdateTimer?.cancel();
    _baseAmountChangedFeeUpdateTimer?.cancel();

    cryptoAmountController.removeListener(onCryptoAmountChanged);
    baseAmountController.removeListener(_baseAmountChanged);

    sendToController.dispose();
    cryptoAmountController.dispose();
    baseAmountController.dispose();
    noteController.dispose();
    feeController.dispose();

    _noteFocusNode.dispose();
    _addressFocusNode.dispose();
    _cryptoFocus.dispose();
    _baseFocus.dispose();
    super.dispose();
  }

